using System;
using System.Collections.Generic;
using System.Collections.Immutable;
using System.Diagnostics;
using System.Linq;
using Microsoft.CodeAnalysis.CSharp.Symbols;
using Microsoft.CodeAnalysis.PooledObjects;
using Roslyn.Utilities;

namespace Microsoft.CodeAnalysis.CSharp
{
    /// <summary>
    /// Unified strategy for symbol resolution across different binding contexts.
    /// Consolidates common symbol lookup patterns used in expression binding,
    /// type resolution, and member access.
    /// </summary>
    internal sealed class UnifiedSymbolResolver
    {
        private readonly Binder _binder;
        private readonly ISymbolResolutionStrategy _strategy;

        internal UnifiedSymbolResolver(Binder binder, ISymbolResolutionStrategy strategy)
        {
            Debug.Assert(binder != null);
            Debug.Assert(strategy != null);
            _binder = binder;
            _strategy = strategy;
        }

        /// <summary>
        /// Resolves a symbol using the configured strategy by walking the scope chain.
        /// </summary>
        /// <param name="name">The name to look up.</param>
        /// <param name="arity">The arity (number of type parameters).</param>
        /// <param name="basesBeingResolved">The type bases being resolved (for circular reference detection).</param>
        /// <param name="options">The lookup options.</param>
        /// <param name="diagnose">Whether to collect diagnostic information.</param>
        /// <param name="useSiteInfo">Use-site diagnostic information.</param>
        /// <returns>The resolution result containing found symbols and diagnostics.</returns>
        internal SymbolResolutionResult Resolve(
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            LookupOptions options,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            Debug.Assert(!string.IsNullOrEmpty(name));
            Debug.Assert(arity >= 0);
            Debug.Assert(options.AreValid());

            var result = new SymbolResolutionResult();
            var lookupResult = LookupResult.GetInstance();

            try
            {
                // Walk through the scope chain
                Binder binder = null;
                for (var scope = _binder; scope != null && !result.IsComplete; scope = scope.Next)
                {
                    var scopeResult = LookupResult.GetInstance();
                    try
                    {
                        // Delegate to strategy for single-scope resolution
                        _strategy.ResolveSingleScope(
                            scope,
                            scopeResult,
                            name,
                            arity,
                            basesBeingResolved,
                            options,
                            _binder,
                            diagnose,
                            ref useSiteInfo);

                        // Merge results according to strategy
                        if (binder != null)
                        {
                            result.MergeResults(lookupResult, scopeResult);
                        }
                        else
                        {
                            lookupResult.SetFrom(scopeResult);
                            if (!lookupResult.IsClear)
                            {
                                binder = scope;
                            }
                        }

                        // Apply scope termination rules
                        if (_strategy.ShouldTerminateSearch(scope, lookupResult, options))
                        {
                            result.TerminateSearch();
                        }
                    }
                    finally
                    {
                        scopeResult.Free();
                    }
                }

                // Populate the result with final symbols and diagnostics
                result.SetLookupResult(lookupResult);
            }
            finally
            {
                lookupResult.Free();
            }

            return result;
        }
    }

    /// <summary>
    /// Strategy interface for symbol resolution in different contexts.
    /// Implementations define how symbols are resolved within a single scope
    /// and when the search should terminate.
    /// </summary>
    internal interface ISymbolResolutionStrategy
    {
        /// <summary>
        /// Resolves symbols within a single scope using this strategy.
        /// </summary>
        void ResolveSingleScope(
            Binder scope,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            LookupOptions options,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo);

        /// <summary>
        /// Determines whether the search should terminate after the current scope.
        /// </summary>
        bool ShouldTerminateSearch(
            Binder scope,
            LookupResult result,
            LookupOptions options);
    }

    /// <summary>
    /// Strategy for type resolution (e.g., in base classes, constraint clauses).
    /// Searches for type symbols and stops when a viable type is found.
    /// </summary>
    internal sealed class TypeResolutionStrategy : ISymbolResolutionStrategy
    {
        public void ResolveSingleScope(
            Binder scope,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            LookupOptions options,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            scope.LookupSymbolsInSingleBinder(
                result,
                name,
                arity,
                basesBeingResolved,
                options,
                originalBinder,
                diagnose,
                ref useSiteInfo);
        }

        public bool ShouldTerminateSearch(
            Binder scope,
            LookupResult result,
            LookupOptions options)
        {
            // Terminate if we found a viable result
            return result.IsMultiViable;
        }
    }

    /// <summary>
    /// Strategy for member access (e.g., in method calls, property access).
    /// Searches for member symbols in types or namespaces with appropriate
    /// visibility and accessibility checks.
    /// </summary>
    internal sealed class MemberAccessStrategy : ISymbolResolutionStrategy
    {
        private readonly NamespaceOrTypeSymbol _qualifier;

        internal MemberAccessStrategy(NamespaceOrTypeSymbol qualifier)
        {
            _qualifier = qualifier;
        }

        public void ResolveSingleScope(
            Binder scope,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            LookupOptions options,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            scope.LookupMembersInternal(
                result,
                _qualifier,
                name,
                arity,
                basesBeingResolved,
                options,
                originalBinder,
                diagnose,
                ref useSiteInfo);
        }

        public bool ShouldTerminateSearch(
            Binder scope,
            LookupResult result,
            LookupOptions options)
        {
            // For member access, terminate if we found viable members
            // Member resolution is typically scoped to the qualifier type
            return result.IsMultiViable;
        }
    }

    /// <summary>
    /// Strategy for namespace resolution (e.g., in qualified names, imports).
    /// Searches for symbols accessible through using directives and aliases.
    /// </summary>
    internal sealed class NamespaceResolutionStrategy : ISymbolResolutionStrategy
    {
        public void ResolveSingleScope(
            Binder scope,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            LookupOptions options,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            scope.LookupSymbolsInSingleBinder(
                result,
                name,
                arity,
                basesBeingResolved,
                options,
                originalBinder,
                diagnose,
                ref useSiteInfo);
        }

        public bool ShouldTerminateSearch(
            Binder scope,
            LookupResult result,
            LookupOptions options)
        {
            // Terminate on viable results
            return result.IsMultiViable;
        }
    }

    /// <summary>
    /// Encapsulates the result of symbol resolution including found symbols
    /// and diagnostic information.
    /// </summary>
    internal sealed class SymbolResolutionResult
    {
        private LookupResult _lookupResult;
        private bool _isComplete = false;

        /// <summary>
        /// Gets the symbols found during resolution.
        /// </summary>
        internal ImmutableArray<Symbol> Symbols
        {
            get
            {
                return _lookupResult?.Symbols ?? ImmutableArray<Symbol>.Empty;
            }
        }

        /// <summary>
        /// Gets the kind of result (Viable, Inaccessible, NonViable, Empty).
        /// </summary>
        internal LookupResultKind Kind
        {
            get
            {
                return _lookupResult?.Kind ?? LookupResultKind.Empty;
            }
        }

        /// <summary>
        /// Gets the error information if the result is non-viable or inaccessible.
        /// </summary>
        internal DiagnosticInfo Error
        {
            get
            {
                return _lookupResult?.Error;
            }
        }

        /// <summary>
        /// Gets a value indicating whether the search is complete.
        /// </summary>
        internal bool IsComplete
        {
            get
            {
                return _isComplete;
            }
        }

        /// <summary>
        /// Sets the lookup result from the resolution process.
        /// </summary>
        internal void SetLookupResult(LookupResult result)
        {
            _lookupResult = result;
        }

        /// <summary>
        /// Merges results from consecutive scopes.
        /// </summary>
        internal void MergeResults(LookupResult target, LookupResult source)
        {
            if (!source.IsClear)
            {
                target.MergeEqual(source);
            }
        }

        /// <summary>
        /// Marks the search as complete.
        /// </summary>
        internal void TerminateSearch()
        {
            _isComplete = true;
        }

        /// <summary>
        /// Gets a value indicating whether any symbols were found.
        /// </summary>
        internal bool HasSymbols
        {
            get
            {
                return _lookupResult != null && _lookupResult.Symbols.Count > 0;
            }
        }

        /// <summary>
        /// Gets a value indicating whether the result is viable (no errors).
        /// </summary>
        internal bool IsViable
        {
            get
            {
                return _lookupResult != null && _lookupResult.Kind == LookupResultKind.Viable;
            }
        }
    }
}

