using System;
using System.Collections.Immutable;
using Microsoft.CodeAnalysis.CSharp.Symbols;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.CSharp.Test.Utilities;
using Microsoft.CodeAnalysis.Text;
using Roslyn.Test.Utilities;
using Xunit;

namespace Microsoft.CodeAnalysis.CSharp.UnitTests.Binder
{
    public class UnifiedSymbolResolverTests : CSharpTestBase
    {
        [Fact]
        public void TestTypeResolutionStrategy_FindsViableType()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        void Method()
        {
            var x = typeof(string);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var tree = compilation.SyntaxTrees[0];
            var root = tree.GetCompilationUnitSyntax();
            var model = compilation.GetSemanticModel(tree);

            // Verify that compilation succeeds
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestMemberAccessStrategy_FindsMembers()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        public void Method() { }
        public int Property { get; set; }

        void TestAccess()
        {
            Method();
            var p = Property;
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestNamespaceResolutionStrategy_FindsNamespaceMembers()
        {
            var source = @"
namespace System
{
    class TestClass
    {
        void Method()
        {
            var t = typeof(System.String);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestScopeChainWalking_LocalVariables()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        void Method()
        {
            int x = 5;
            {
                int y = 10;
                var sum = x + y;  // Should find both x and y
            }
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestScopeChainWalking_InheritedMembers()
        {
            var source = @"
namespace N
{
    class Base
    {
        protected void BaseMethod() { }
        protected int BaseProperty { get; set; }
    }

    class Derived : Base
    {
        void Method()
        {
            BaseMethod();           // Should find inherited method
            var p = BaseProperty;   // Should find inherited property
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestMultipleSymbolsWithSameName()
        {
            var source = @"
namespace N
{
    class Base
    {
        public virtual void Foo() { }
    }

    class Derived : Base
    {
        public override void Foo() { }

        public void Foo(int x) { }

        void Method()
        {
            Foo();      // Should resolve
            Foo(5);     // Should resolve
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestAccessibilityRules()
        {
            var source = @"
namespace N
{
    class Outer
    {
        private int _privateField = 5;
        public int PublicField = 10;

        void Method()
        {
            var x = _privateField;
            var y = PublicField;
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestGenericTypeResolution()
        {
            var source = @"
namespace N
{
    class Generic<T>
    {
        void Method()
        {
            var t = typeof(T);
        }
    }

    class Usage
    {
        void Test()
        {
            var g = typeof(Generic<int>);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestNestedTypeResolution()
        {
            var source = @"
namespace N
{
    class Outer
    {
        class Inner
        {
            void InnerMethod() { }
        }

        void OuterMethod()
        {
            var t = typeof(Inner);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestUsingDirectiveResolution()
        {
            var source = @"
using System;

namespace N
{
    class MyClass
    {
        void Method()
        {
            var s = typeof(String);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestAliasResolution()
        {
            var source = @"
using MyString = System.String;

namespace N
{
    class MyClass
    {
        void Method()
        {
            var s = typeof(MyString);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestInterfaceImplementationMembers()
        {
            var source = @"
namespace N
{
    interface IMyInterface
    {
        void Method();
        int Property { get; set; }
    }

    class Implementation : IMyInterface
    {
        public void Method() { }
        public int Property { get; set; }

        void Test()
        {
            Method();
            var p = Property;
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestTypeParameterConstraintResolution()
        {
            var source = @"
namespace N
{
    interface IConstraint
    {
        void ConstrainedMethod();
    }

    class Generic<T> where T : IConstraint
    {
        void Method(T t)
        {
            t.ConstrainedMethod();
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestExtensionMethodResolution()
        {
            var source = @"
namespace N
{
    static class Extensions
    {
        public static void ExtMethod(this string s) { }
    }

    class MyClass
    {
        void Method()
        {
            string s = ""test"";
            s.ExtMethod();  // Should find extension method
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestSymbolHiding()
        {
            var source = @"
namespace N
{
    class Base
    {
        public void Method() { }
    }

    class Derived : Base
    {
        new public void Method() { }  // Hiding base method

        void Test()
        {
            Method();  // Should find derived method
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestNamespaceQualifiedLookup()
        {
            var source = @"
namespace N1
{
    class C { }
}

namespace N2
{
    class Usage
    {
        void Method()
        {
            var t = typeof(N1.C);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestStaticMemberAccess()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        public static void StaticMethod() { }
        public static int StaticProperty { get; set; }

        void Instance()
        {
            MyClass.StaticMethod();
            var p = MyClass.StaticProperty;
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestLambdaParameterResolution()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        void Method()
        {
            var func = (int x, int y) => x + y;
            var result = func(5, 10);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestInaccessibleMemberError()
        {
            var source = @"
namespace N
{
    class Outer
    {
        private void PrivateMethod() { }
    }

    class Other
    {
        void Method()
        {
            var o = new Outer();
            o.PrivateMethod();  // Error: inaccessible
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.NotEmpty(diagnostics);  // Should have accessibility error
        }

        [Fact]
        public void TestUndefinedSymbolError()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        void Method()
        {
            var x = UndefinedVariable;  // Error: undefined
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.NotEmpty(diagnostics);  // Should have undefined symbol error
        }

        [Fact]
        public void TestAmbiguousSymbolError()
        {
            var source = @"
namespace N
{
    class Base
    {
        public void Ambiguous() { }
    }

    interface I
    {
        void Ambiguous();
    }

    class Derived : Base, I
    {
        void Method()
        {
            Ambiguous();  // May be ambiguous depending on resolution
        }
    }
}
";
            var compilation = CreateCompilation(source);
            // This should either compile or have a specific diagnostic
            var diagnostics = compilation.GetDiagnostics();
            // Just verify compilation doesn't crash
            Assert.NotNull(diagnostics);
        }
    }
}

