251:         ///    looking further. Otherwise, if we find viable overload(s) we add them into the result.
252:         ///    
253:         /// Note that indexers are not supported in script but we deal with them here to handle errors.
254:         /// </remarks>
255:         protected void LookupMembersInSubmissions(LookupResult result, TypeSymbol submissionClass, CompilationUnitSyntax declarationSyntax, bool inUsings, string name, int arity, ConsList<TypeSymbol> basesBeingResolved,
256:             LookupOptions options, Binder originalBinder, bool diagnose, ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
257:         {
258:             LookupResult submissionSymbols = LookupResult.GetInstance();
259:             LookupResult nonViable = LookupResult.GetInstance();
260:             SymbolKind? lookingForOverloadsOfKind = null;
261: 
262:             bool isSubmissionTree = Compilation.IsSubmissionSyntaxTree(declarationSyntax.SyntaxTree);
263: 
264:             // TODO: optimize lookup (there might be many interactions in the chain)
265:             for (CSharpCompilation submission = Compilation; submission != null; submission = submission.PreviousSubmission)
266:             {
267:                 submissionSymbols.Clear();
268: 
269:                 var isCurrentSubmission = submission == Compilation;
270:                 var considerUsings = !(isCurrentSubmission && inUsings);
271: 
272:                 Imports submissionImports;
273:                 if (!considerUsings)
274:                 {
275:                     submissionImports = Imports.Empty;
276:                 }
277:                 else if (isSubmissionTree)
278:                 {
279:                     submissionImports = submission.GetSubmissionImports();
280:                 }
281:                 else if (isCurrentSubmission)
282:                 {
283:                     submissionImports = ((SourceNamespaceSymbol)Compilation.SourceModule.GlobalNamespace).GetImports(declarationSyntax, basesBeingResolved);
284:                 }
285:                 else
286:                 {
287:                     submissionImports = Imports.Empty;
288:                 }
289: 
290:                 // If a viable using alias and a matching member are both defined in the submission an error is reported elsewhere.
291:                 // Ignore the member in such case.
292:                 if ((options & LookupOptions.NamespaceAliasesOnly) == 0 && (object)submission.ScriptClass != null)
293:                 {
294:                     LookupMembersWithoutInheritance(submissionSymbols, submission.ScriptClass, name, arity, options, originalBinder, submissionClass, diagnose, ref useSiteInfo, basesBeingResolved);
295: 
296:                     // NB: It doesn't matter that submissionImports hasn't been expanded since we're not actually using the alias target. 
297:                     if (submissionSymbols.IsMultiViable &&
298:                         considerUsings &&
299:                         IsUsingAlias(submissionImports.UsingAliases, name, originalBinder.IsSemanticModelBinder))
300:                     {
301:                         // using alias is ambiguous with another definition within the same submission iff the other definition is a 0-ary type or a non-type:
302:                         Symbol existingDefinition = submissionSymbols.Symbols.First();
303:                         if (existingDefinition.Kind != SymbolKind.NamedType || arity == 0)
304:                         {
305:                             CSDiagnosticInfo diagInfo = new CSDiagnosticInfo(ErrorCode.ERR_ConflictingAliasAndDefinition, name, existingDefinition.GetKindText());
306:                             var error = new ExtendedErrorTypeSymbol((NamespaceOrTypeSymbol)null, name, arity, diagInfo, unreported: true);
307:                             result.SetFrom(LookupResult.Good(error)); // force lookup to be done w/ error symbol as result
308:                             break;
309:                         }
310:                     }
311:                 }
312: 
313:                 if (!submissionSymbols.IsMultiViable && considerUsings)
314:                 {
315:                     if (!isCurrentSubmission)
316:                     {
317:                         submissionImports = Imports.ExpandPreviousSubmissionImports(submissionImports, Compilation);
318:                     }
319: 
320:                     // NB: We diverge from InContainerBinder here and only look in aliases.
321:                     // In submissions, regular usings are bubbled up to the outermost scope.
322:                     LookupSymbolInAliases(submissionImports.UsingAliases, submissionImports.ExternAliases, originalBinder, submissionSymbols, name, arity, basesBeingResolved, options, diagnose, ref useSiteInfo);
323:                 }
