325:                 if (lookingForOverloadsOfKind == null)
326:                 {
327:                     if (!submissionSymbols.IsMultiViable)
328:                     {
329:                         // skip non-viable members, but remember them in case no viable members are found in previous submissions:
330:                         nonViable.MergePrioritized(submissionSymbols);
331:                         continue;
332:                     }
333: 
334:                     result.MergeEqual(submissionSymbols);
335: 
336:                     Symbol firstSymbol = submissionSymbols.Symbols.First();
337:                     if (!IsMethodOrIndexer(firstSymbol))
338:                     {
339:                         break;
340:                     }
341: 
342:                     // we are now looking for any kind of member regardless of the original binding restrictions:
343:                     options = options & ~(LookupOptions.MustBeInvocableIfMember | LookupOptions.NamespacesOrTypesOnly);
344:                     lookingForOverloadsOfKind = firstSymbol.Kind;
345:                 }
346:                 else
347:                 {
348:                     // found a non-method - the overload set is final now
349:                     if (submissionSymbols.Symbols.Count > 0 && submissionSymbols.Symbols.First().Kind != lookingForOverloadsOfKind.Value)
350:                     {
351:                         break;
352:                     }
353: 
354:                     // found a viable overload:
355:                     if (submissionSymbols.IsMultiViable)
356:                     {
357:                         // merge overloads:
358:                         Debug.Assert(result.Symbols.All(IsMethodOrIndexer));
359:                         result.MergeEqual(submissionSymbols);
360:                     }
361:                 }
362:             }
363: 
364:             if (result.Symbols.Count == 0)
365:             {
366:                 result.SetFrom(nonViable);
367:             }
368: 
369:             submissionSymbols.Free();
370:             nonViable.Free();
371:         }
