using System;
using System.Collections.Immutable;
using Microsoft.CodeAnalysis.CSharp.Symbols;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.CSharp.Test.Utilities;
using Microsoft.CodeAnalysis.Text;
using Roslyn.Test.Utilities;
using Xunit;

namespace Microsoft.CodeAnalysis.CSharp.UnitTests.Binder
{
    public class UnifiedSymbolResolverTests : CSharpTestBase
    {
        [Fact]
        public void TestTypeResolutionStrategy_FindsViableType()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        void Method()
        {
            var x = typeof(string);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var tree = compilation.SyntaxTrees[0];
            var root = tree.GetCompilationUnitSyntax();
            var model = compilation.GetSemanticModel(tree);

            // Verify that compilation succeeds
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestMemberAccessStrategy_FindsMembers()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        public void Method() { }
        public int Property { get; set; }

        void TestAccess()
        {
            Method();
            var p = Property;
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestNamespaceResolutionStrategy_FindsNamespaceMembers()
        {
            var source = @"
namespace System
{
    class TestClass
    {
        void Method()
        {
            var t = typeof(System.String);
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestScopeChainWalking_LocalVariables()
        {
            var source = @"
namespace N
{
    class MyClass
    {
        void Method()
        {
            int x = 5;
            {
                int y = 10;
                var sum = x + y;  // Should find both x and y
            }
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestScopeChainWalking_InheritedMembers()
        {
            var source = @"
namespace N
{
    class Base
    {
        protected void BaseMethod() { }
        protected int BaseProperty { get; set; }
    }

    class Derived : Base
    {
        void Method()
        {
            BaseMethod();           // Should find inherited method
            var p = BaseProperty;   // Should find inherited property
        }
    }
}
";
            var compilation = CreateCompilation(source);
            var diagnostics = compilation.GetDiagnostics();
            Assert.Empty(diagnostics);
        }

        [Fact]
        public void TestMultipleSymbolsWithSameName()
        {
            var source = @"
namespace N
{
    class Base
    {
        public virtual void Foo() { }
    }

    class Derived : Base
    {
        public override void Foo() { }

        public void Foo(int x) { }

        void Method()
        {
            Foo();      // Should resolve
            Foo(5);     // Should resolve
        }
