251:         /// <summary>
252:         /// Merge another result with this one, with the symbols combined if both
253:         /// this and other are viable. Otherwise the highest priority result wins (this if equal 
254:         /// priority and non-viable.)
255:         /// </summary>
256:         internal void MergeEqual(LookupResult other)
257:         {
258:             if (Kind > other.Kind)
259:             {
260:                 return;
261:             }
262:             else if (other.Kind > Kind)
263:             {
264:                 this.SetFrom(other);
265:             }
266:             else if (Kind != LookupResultKind.Viable)
267:             {
268:                 // this makes the operator not symmetrical, but so far we do not care.
269:                 // it is really a matter of which error gets reported.
270:                 return;
271:             }
272:             else
273:             {
274:                 // Merging two viable results together. We will always end up with at least two symbols.
275:                 _symbolList.AddRange(other._symbolList);
276:             }
277:         }
278: 
279:         internal void MergeEqual(SingleLookupResult result)
280:         {
281:             if (Kind > result.Kind)
282:             {
283:                 // existing result is better
284:             }
285:             else if (result.Kind > Kind)
286:             {
287:                 this.SetFrom(result);
288:             }
289:             else if ((object)result.Symbol != null)
290:             {
291:                 // Same goodness. Include all symbols
292:                 _symbolList.Add(result.Symbol);
293:             }
294:         }
