                diagnose,
                ref useSiteInfo);
        }

        public bool ShouldTerminateSearch(
            Binder scope,
            LookupResult result,
            LookupOptions options)
        {
            // Terminate on viable results
            return result.IsMultiViable;
        }
    }

    /// <summary>
    /// Encapsulates the result of symbol resolution including found symbols
    /// and diagnostic information.
    /// </summary>
    internal sealed class SymbolResolutionResult
    {
        private LookupResult _lookupResult;
        private bool _isComplete = false;

        /// <summary>
        /// Gets the symbols found during resolution.
        /// </summary>
        internal ImmutableArray<Symbol> Symbols
        {
            get
            {
                return _lookupResult?.Symbols ?? ImmutableArray<Symbol>.Empty;
            }
        }

        /// <summary>
        /// Gets the kind of result (Viable, Inaccessible, NonViable, Empty).
        /// </summary>
        internal LookupResultKind Kind
        {
            get
            {
                return _lookupResult?.Kind ?? LookupResultKind.Empty;
            }
        }

        /// <summary>
        /// Gets the error information if the result is non-viable or inaccessible.
        /// </summary>
        internal DiagnosticInfo Error
        {
            get
            {
                return _lookupResult?.Error;
            }
        }

        /// <summary>
        /// Gets a value indicating whether the search is complete.
        /// </summary>
        internal bool IsComplete
        {
            get
            {
                return _isComplete;
            }
        }

        /// <summary>
        /// Sets the lookup result from the resolution process.
        /// </summary>
        internal void SetLookupResult(LookupResult result)
        {
            _lookupResult = result;
        }

        /// <summary>
        /// Merges results from consecutive scopes.
        /// </summary>
        internal void MergeResults(LookupResult target, LookupResult source)
        {
            if (!source.IsClear)
            {
                target.MergeEqual(source);
            }
        }

        /// <summary>
        /// Marks the search as complete.
        /// </summary>
        internal void TerminateSearch()
        {
            _isComplete = true;
        }

        /// <summary>
        /// Gets a value indicating whether any symbols were found.
        /// </summary>
        internal bool HasSymbols
        {
            get
            {
                return _lookupResult != null && _lookupResult.Symbols.Count > 0;
            }
        }

        /// <summary>
        /// Gets a value indicating whether the result is viable (no errors).
        /// </summary>
        internal bool IsViable
        {
            get
            {
                return _lookupResult != null && _lookupResult.Kind == LookupResultKind.Viable;
            }
        }
    }
