f(String);\n        }\n    }\n}\n\";\n            var compilation = CreateCompilation(source);\n            var diagnostics = compilation.GetDiagnostics();\n            Assert.Empty(diagnostics);\n        }\n\n        [Fact]\n        public void TestAliasResolution()\n        {\n            var source = @\"\nusing MyString = System.String;\n\nnamespace N\n{\n    class MyClass\n    {\n        void Method()\n        {\n            var s = typeof(MyString);\n        }\n    }\n}\n\";\n            var compilation = CreateCompilation(source);\n            var diagnostics = compilation.GetDiagnostics();\n            Assert.Empty(diagnostics);\n        }\n\n        [Fact]\n        public void TestInterfaceImplementationMembers()\n        {\n            var source = @\"\nnamespace N\n{\n    interface IMyInterface\n    {\n        void Method();\n        int Property { get; set; }\n    }\n\n    class Implementation : IMyInterface\n    {\n        public void Method() { }\n        public int Property { get; set; }\n\n        void Test()\n        {\n            Method();\n            var p = Property;\n        }\n    }\n}\n\";\n            var compilation = CreateCompilation(source);\n            var diagnostics = compilation.GetDiagnostics();\n            Assert.Empty(diagnostics);\n        }\n\n        [Fact]\n        public void TestTypeParameterConstraintResolution()\n        {\n            var source = @\"\nnamespace N\n{\n    interface IConstraint\n    {\n        void ConstrainedMethod();\n    }\n\n    class Generic<T> where T : IConstraint\n    {\n        void Method(T t)\n        {\n            t.ConstrainedMethod();\n        }\n    }\n}\n\";\n            var compilation = CreateCompilation(source);\n            var diagnostics = compilation.GetDiagnostics();\n            Assert.Empty(diagnostics);\n        }\n\n        [Fact]\n        public void TestExtensionMethodResolution()\n        {\n            var source = @\"\nnamespace N\n{\n    static class Extensions\n    {\n